import modal

app = modal.App(name="check-volume")

volume = modal.Volume.from_name("modal-doc-ocr-pipeline-vol")


@app.function(volumes={"/ocr_output": volume})
def read_summary():
    import json

    with open("/ocr_output/summary.json", "r") as f:
        return json.load(f)


@app.local_entrypoint()
def main():
    summary = read_summary.remote()
    print("Summary from Volume:")
    print(json.dumps(summary, indent=2))
